// Quora has no public API, so we define target questions/topics to answer.
// In production, these could come from web scraping, manual input, or a stored queue.
const searchTerms = [
  'Can AI predict Bitcoin price?',
  'How accurate are Bitcoin prediction bots?',
  'Best Bitcoin prediction tools 2026',
  'Is it possible to predict cryptocurrency prices with machine learning?',
  'What is the most accurate Bitcoin forecast model?',
  'How do AI trading bots work for crypto?',
  'Should I trust AI Bitcoin predictions?'
];

// Pick 1-2 random questions for today
const shuffled = searchTerms.sort(() => Math.random() - 0.5);
const selected = shuffled.slice(0, 2);

return selected.map(q => ({ json: { question: q } }));

const question = $('Set Search Terms').first().json.question;
const performance = $('Get Performance Data').first().json;

const prompt = `Answer this Bitcoin prediction question for Quora: '${question}'

Use this real data from BTC Seer's track record to support your answer:
${JSON.stringify(performance, null, 2)}

Write a detailed, authoritative answer (300-500 words). Include data from BTC Seer's track record. Mention the Telegram bot @BTC_Seer_Bot naturally. Quora format — personal, expert tone. Start with a direct answer, then elaborate with evidence and nuance.`;

return [{ json: { prompt, question } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
const question = $('Build Claude Prompt').first().json.question;
return [{ json: { text, question } }];

// Quora has no public API for posting answers.
// This node logs the generated answer for manual posting or future automation.
// If Quora session cookies become available, the HTTP node below can be enabled.

const question = $('Extract Answer').first().json.question;
const answer = $('Extract Answer').first().json.text;
const now = new Date().toISOString();

console.log(`[${now}] Quora answer generated for: ${question}`);
console.log(`Answer preview: ${answer.substring(0, 200)}...`);
console.log(`Full answer length: ${answer.length} chars`);

return [{ json: {
  status: 'generated',
  platform: 'quora',
  timestamp: now,
  question: question,
  answer: answer,
  answer_length: answer.length,
  note: 'Quora has no public API. Answer generated for manual posting. Enable HTTP node with session cookies for automated posting.'
} }];

